#nullable enable // autogenerated

using MVZ2Logic.Contents.Buffs.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Games;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Entities;
using PVZEngine.Level;
using UnityEngine;

namespace MVZ2Logic.Entities
{
    public static class LogicEntityExt
    {
        #region 护甲
        public static Vector3 GetArmorDisplayPosition(this Entity entity, NamespaceID slot, NamespaceID armorID)
        {
            var shapeID = entity.GetShapeID();
            if (shapeID != null)
            {
                var shapeDef = Global.Game.GetShapeDefinition(shapeID);
                if (shapeDef != null)
                {
                    var offset = shapeDef.GetArmorPosition(slot, armorID);
                    offset.Scale(entity.GetFinalDisplayScale());
                    return offset + entity.Position;
                }
            }
            var bounds = entity.GetBounds();
            return bounds.center + Vector3.up * bounds.extents.y;
        }
        public static Vector3 GetArmorDisplayScale(this Entity entity, NamespaceID slot, NamespaceID armorID)
        {
            var shapeID = entity.GetShapeID();
            if (shapeID != null)
            {
                var shapeDef = Global.Game.GetShapeDefinition(shapeID);
                if (shapeDef != null)
                {
                    var offset = shapeDef.GetArmorScale(slot, armorID);
                    offset.Scale(entity.GetFinalDisplayScale());
                    return offset;
                }
            }
            return Vector3.one;
        }
        public static Vector3 GetArmorOffset(this Entity entity, NamespaceID slot, NamespaceID armorID)
        {
            var shapeID = entity.GetShapeID();
            if (shapeID != null)
            {
                var shapeMeta = Global.Game.GetShapeDefinition(shapeID);
                if (shapeMeta != null)
                {
                    return shapeMeta.GetArmorPosition(slot, armorID);
                }
            }
            return Vector3.zero;
        }
        public static Vector3 GetArmorScale(this Entity entity, NamespaceID slot, NamespaceID armorID)
        {
            var shapeID = entity.GetShapeID();
            if (shapeID != null)
            {
                var shapeDef = Global.Game.GetShapeDefinition(shapeID);
                if (shapeDef != null)
                {
                    return shapeDef.GetArmorScale(slot, armorID);
                }
            }
            return Vector3.one;
        }
        #endregion

        #region 音效
        public static void PlaySound(this Entity entity, NamespaceID soundID, float pitch = 1, float volume = 1)
        {
            entity.Level.PlaySound(soundID, entity.Position, pitch, volume);
        }
        public static void PlaySoundIfNotNull(this Entity entity, NamespaceID? soundID, float pitch = 1, float volume = 1)
        {
            if (soundID == null)
                return;
            entity.PlaySound(soundID, pitch, volume);
        }
        public static void PlayCrySound(this Entity entity, NamespaceID soundID, float pitchMultiplier = 1, float volume = 1)
        {
            var pitch = entity.GetCryPitch() * pitchMultiplier;
            entity.PlaySound(soundID, pitch, volume);
        }
        public static void PlayDeathSound(this Entity entity)
        {
            var deathSound = entity.GetDeathSound();
            if (NamespaceID.IsValid(deathSound))
                entity.PlayCrySound(deathSound);
        }
        #endregion

        #region 阵营
        public static bool IsFriendlyEntity(this Entity entity)
        {
            return entity.Level.IsFriendlyFaction(entity.GetFaction());
        }
        public static bool IsHostileEntity(this Entity entity)
        {
            return entity.Level.IsHostileFaction(entity.GetFaction());
        }
        public static bool IsFriendlyFaction(this LevelEngine level, int faction)
        {
            return EngineEntityExt.IsFriendly(faction, level.Option.LeftFaction);
        }
        public static bool IsHostileFaction(this LevelEngine level, int faction)
        {
            return !level.IsFriendlyFaction(faction);
        }
        #endregion

        #region 可伤害实体
        public static bool IsVulnerableEntity(this Entity entity)
        {
            return entity.Type == EntityTypes.PLANT || entity.Type == EntityTypes.ENEMY || entity.Type == EntityTypes.OBSTACLE || entity.Type == EntityTypes.BOSS;
        }
        #endregion

        #region 存活
        public static bool IsAliveEnemy(this Entity entity)
        {
            if (entity.Type != EntityTypes.ENEMY)
                return false;
            if (entity.IsDead && !entity.AssumeAlive())
                return false;
            if (entity.IsNotActiveEnemy())
                return false;
            if (!entity.IsHostile(entity.Level.Option.LeftFaction))
                return false;
            return true;
        }
        #endregion

        #region 伤害闪烁
        public static void DamageBlink(this Entity entity)
        {
            if (entity != null && !entity.HasBuff<DamageColorBuff>())
                entity.AddBuff<DamageColorBuff>();
        }
        #endregion

        #region 镜像列
        public static int GetMirroredColumn(this Entity entity, int column, bool whenFaceRight)
        {
            if (entity.IsFacingLeft() == whenFaceRight)
            {
                return entity.Level.GetMaxColumnCount() - column - 1;
            }
            return column;
        }
        public static float GetMirroredX(this Entity entity, float x, bool whenFaceRight)
        {
            if (entity.IsFacingLeft() == whenFaceRight)
            {
                return entity.Level.GetLawnCenterX() * 2 - x;
            }
            return x;
        }
        #endregion

        public static void UpdateAnimationParameters(this Entity entity, int state)
        {
            var behaviour = entity.Definition.GetBehaviour<IEnemyAnimationBehaviour>();
            if (behaviour != null)
            {
                behaviour.UpdateAnimationParameters(entity, state);
            }
        }
    }
}